//! Stoplight algebra — re-export shim over the canonical `gnosis-helix`
//! crate.
//!
//! This module used to host its own port of
//! `Gnosis.Civil.QuasicrystalStoplightTiming`. Per the FOIL HELIX SSOT
//! standard (see `foil-runtime/HELIX_APOTHEOSIS.md` and the new
//! `open-source/gnosis/gnosis-helix/` crate), the algebra lives in one
//! place: `gnosis_helix`. Every downstream Stoplight consumer (this crate,
//! gnosis-uring, gnosis-antiqueue, etc.) re-exports from there so the math
//! cannot silently diverge across runtimes (Aether SSOT trap, CLAUDE.md
//! memory).
//!
//! Public symbol names are preserved byte-for-byte (`Stoplight`,
//! `travel_time`, `arrival_phase`, `sees_green`, `corridor_all_green`,
//! `earliest_green_start`, `phase_compensating_offset`) so existing
//! `gnosis_frf::stoplight::*` callers keep compiling without churn.

pub use gnosis_helix::{
    Stoplight, aligned_count, arrival_phase, corridor_all_green, earliest_green_start,
    phase_compensating_offset, sees_green, travel_time,
};

#[cfg(test)]
mod tests {
    use super::*;

    /// Lean witness `phi_corridor_lines_up_at_zero` survives the re-export.
    #[test]
    fn phi_corridor_lines_up_at_zero_via_reexport() {
        let phi = [
            Stoplight::new(60, 15, 5, 55, 1),
            Stoplight::new(60, 15, 31, 89, 1),
            Stoplight::new(60, 15, 36, 144, 1),
            Stoplight::new(60, 15, 7, 233, 1),
        ];
        assert!(corridor_all_green(0, &phi));
    }
}
